async fn calc_team_score(
    conn: &DatabaseConnection, team: &Model, game_id: i64,
) -> Result<i32, DbErr> {
    let mut sql = super::submission::Entity::find()
        .filter(super::submission::Column::TeamId.eq(team.id))
        .filter(super::submission::Column::Solved.eq(true));
    sql = sql
        .join(
            JoinType::InnerJoin,
            super::submission::Relation::Challenge.def(),
        )
        .filter(super::challenge::Column::GameId.eq(game_id))
        .filter(super::challenge::Column::Hidden.eq(false))
        .select_only()
        .column_as(super::challenge::Column::CurrentScore, "score")
        .distinct_on([
            (super::submission::Entity, super::submission::Column::TeamId),
            (
                super::submission::Entity,
                super::submission::Column::ChallengeId,
            ),
        ])
        .distinct_on([
            (super::submission::Entity, super::submission::Column::UserId),
            (
                super::submission::Entity,
                super::submission::Column::ChallengeId,
            ),
        ]);
    let res = sql.into_model::<ChallengeScore>().all(conn).await?;
    let mut team_score = 0;
    for challenge_score in res {
        team_score += challenge_score.score
    }
    let extras = extra::get_extras_by_team_id(conn, team.id).await?;
    for extra in extras {
        team_score += extra.score;
    }
    Ok(team_score)
}

pub async fn update_team_score(
    conn: &DatabaseConnection, team: &Model, game_id: i64, last_active_at: DateTime<Utc>,
) -> Result<i32, DbErr> {
    let team_score = calc_team_score(conn, team, game_id).await?;
    let mut active_model = team.clone().into_active_model();
    active_model.score = ActiveValue::Set(team_score);
    active_model.last_active_at = ActiveValue::Set(last_active_at);
    active_model.update(conn).await?;
    Ok(team_score)
}

pub async fn get_team_page_by_game_id(
    conn: &DatabaseConnection, game_id: i64, page: u64, per_page: u64, filter: Option<String>,
    need_audit: Option<bool>,
) -> Result<(Vec<Model>, u64), DbErr> {
    let sql = Entity::find()
        .filter(Column::GameId.eq(game_id))
        .order_by_asc(Column::Id);
    let mut sql = filter_team(sql, filter)?;
    if Some(true) == need_audit {
        sql = sql.filter(Column::State.eq(State::NeedAudit));
    }
    let paginator = sql.paginate(conn, per_page);
    let num_pages = paginator.num_pages().await?;
    let teams = paginator.fetch_page(page - 1).await?;
    let teams = teams.into_iter().map(|team| team.desensitize()).collect();
    Ok((teams, num_pages))
}

fn filter_team(mut sql: Select<Entity>, filter: Option<String>) -> Result<Select<Entity>, DbErr> {
    if let Some(filter) = filter {
        let mut cond = Condition::any();
        if let Ok(num) = filter.parse::<i64>() {
            cond = cond.add(Column::Id.eq(num));
            cond = cond.add(Column::State.eq(num));
        }
        let filter = format!("%{}%", filter.to_ascii_lowercase());
        cond = cond.add(Expr::expr(Func::lower(Expr::col(Column::Name))).like(filter.clone()));
        sql = sql.filter(cond);
    };
    Ok(sql)
}

