pub async fn get_affected_teams_by_challenge_id(
    conn: &DatabaseConnection, challenge_id: i64,
) -> Result<Vec<Model>, DbErr> {
    let submissions = super::submission::Entity::find()
        .filter(super::submission::Column::ChallengeId.eq(challenge_id))
        .filter(super::submission::Column::Solved.eq(true))
        .all(conn)
        .await?;
    let mut team_ids = HashSet::new();
    let mut teams: Vec<Model> = Vec::new();
    for submission in submissions {
        // let user = submission.find_related(User).one(conn).await?;
        let team = submission
            .find_related(User)
            .find_also_related(Entity)
            .one(conn)
            .await?
            .ok_or(DbErr::RecordNotFound("team".to_string()))?
            .1;
        if let Some(team) = team {
            if !team_ids.contains(&team.id) {
                team_ids.insert(team.id);
                teams.push(team);
            }
        }
    }
    Ok(teams)
}

